changeSet.sql:
UPDATE persons SET first_name = TRIM(REPLACE(REPLACE(REPLACE(REPLACE(first_name, ' ? ', ' - '), ' – ', ' - '), ' — ', ' - '), '  ', ' '))
WHERE first_name LIKE '%?%' OR first_name LIKE '%–%' OR first_name LIKE '%—%';

UPDATE persons SET last_name = TRIM(REPLACE(REPLACE(REPLACE(REPLACE(last_name, ' ? ', ' - '), ' – ', ' - '), ' — ', ' - '), '  ', ' '))
WHERE last_name LIKE '%?%' OR last_name LIKE '%–%' OR last_name LIKE '%—%';
